import sys

class Solution:
    def findCelebrity(self, matrix: list[list[bool | None]]) -> int:
        n = len(matrix)
        # Initialize candidate for celebrity
        candidate = 0
        # Find the candidate for celebrity
        for i in range(1, n):
            if matrix[candidate][i]:
                candidate = i
        # Check if the candidate is the celebrity
        for i in range(n):
            if i != candidate:
                if matrix[candidate][i] or not matrix[i][candidate]:
                    return -1
        return candidate

