#include <numeric>
#include <bits/stdc++.h>
using namespace std;

class Solution {
public:
    int findCelebrity(vector<vector<bool>>& matrix) {
        int n = matrix.size();
        int candidate = 0;
        for (int i = 1; i < n; i++) {
            if (matrix[candidate][i]) {
                candidate = i;
            }
        }
        for (int i = 0; i < n; i++) {
            if (i != candidate && (matrix[candidate][i] || !matrix[i][candidate])) {
                return -1;
            }
        }
        return candidate;
    }
};

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int n;
    cin >> n;
    vector<vector<bool>> matrix(n, vector<bool>(n));
    for (int i = 0; i < n; i++) {
        for (int j = 0; j < n; j++) {
            string s;
            cin >> s;
            if (s == "true") {
                matrix[i][j] = true;
            } else if (s == "false") {
                matrix[i][j] = false;
            } else {
                matrix[i][j] = false; // or any other default value
            }
        }
    }
    Solution sol;
    int ans = sol.findCelebrity(matrix);
    cout << ans << "\n";
    return 0;
}
